#[test]
fn test_type_15_blob_length_mismatch() {
    // S-TYPE-015: Blob length validation — corrupt length byte
    // Arrange: encode valid blob
    let v = HalValue::Blob(vec![1, 2, 3, 4]);
    let mut encoded = encode_halvalue(&v);
    // Corrupt the 4-byte length field (bytes 1-4 after type tag 0)
    let fake_len: u32 = 999;
    encoded[1..5].copy_from_slice(&fake_len.to_le_bytes());
    // Act
    let result = decode_halvalue(&encoded);
    // Assert
    assert!(
        matches!(result, Err(HalError::InvalidBlobLength { .. })),
        "expected InvalidBlobLength, got {:?}",
        result
    );
}

#[test]
fn test_type_16_array_type_mismatch() {
    // S-TYPE-016: Array element_type validation — corrupt element_type byte
    // Arrange: encode valid Array, then corrupt element_type tag (byte 1, after TAG_ARRAY)
    let v = HalValue::Array { element_type: HalPinType::S32, data: vec![0, 0, 0, 0] };
    let mut encoded = encode_halvalue(&v);
    encoded[1] = 0xFF; // invalid element_type tag
    // Act
    let result = decode_halvalue(&encoded);
    // Assert
    assert!(
        matches!(result, Err(HalError::TypeMismatch { .. })),
        "expected TypeMismatch, got {:?}",
        result
    );
}

