#[test]
fn test_type_19_nesting_limit() {
    // S-TYPE-019: Array of Blob — decode handles non-scalar element_type
    // Arrange: encode Array { element_type: Blob, data: single encoded empty blob }
    let inner_blob = encode_halvalue(&HalValue::Blob(vec![]));
    let v = HalValue::Array { element_type: HalPinType::Blob, data: inner_blob };
    // Act
    let encoded = encode_halvalue(&v);
    let decoded = decode_halvalue(&encoded).expect("decode Array<Blob> failed");
    // Assert
    match decoded {
        HalValue::Array { element_type, .. } => {
            assert_eq!(element_type, HalPinType::Blob);
        }
        _ => panic!("expected Array, got {:?}", decoded),
    }
}

